INSERT INTO "Collections" ("id","name","description","season","series","edition","release_year","themes","colours","name_friendly") VALUES(129,'The Sewing Shop - Raspberry Edition','Vendula Sewing Shop returns in Raspberry Edition, refreshed in an inspired pink and yellow colourway that’s ready to brighten every outfit. Packed with haberdashery charm, this Shopfront story is all about the joy of making: spools, buttons and tiny atelier details, with layered finishes that feel like a shop window you could get lost in.','SS26','Sewing Shop','Raspberry',2026,NULL,NULL,'Sewing Shop - Raspberry Edition');
INSERT INTO "Collections" ("id","name","description","season","series","edition","release_year","themes","colours","name_friendly") VALUES(130,'Above The Clouds',NULL,'SS26',NULL,NULL,2026,'["hot air balloon"]','["pink","orange"]','Above The Clouds');
INSERT INTO "Collections" ("id","name","description","season","series","edition","release_year","themes","colours","name_friendly") VALUES(131,'Lucky Lanterns','Lunar New Year lights the way in our Lucky Lanterns collection, a playful Shopfront range inspired by ornate Chinese architecture and the sparkle of festival nights. Brimming with lantern motifs, mischievous black cats (they’re lucky for us at Vendula HQ!), and a removable horse charm to honour the Year of the Horse, each piece feels like a pocket parade. Lion puppet embroidery on the Box Bag, gilded frame details, layered lacquer panels and swinging silk tassels add theatrical charm. Every accessory carries a little fortune and a story ready to be worn.','SS26',NULL,NULL,2026,NULL,'["red","gold"]','Lucky Lanterns');
INSERT INTO "Collections" ("id","name","description","season","series","edition","release_year","themes","colours","name_friendly") VALUES(132,'The Chocolate Box',NULL,'SS26',NULL,NULL,2026,'["valentines day"]','["red","pink"]','Chocolate Box');
