INSERT INTO "Shapes" ("id","name","measurements","category","name_friendly","size","description") VALUES(1,'The Tempest Ship Bag','12cm (H) x 26cm (W) x 11cm (D)','["ship","novelty","grab"]','The Tempest Ship Bag','medium','The play may start with a shipwreck but rest assured: the Shakespeare’s Theatre - The Tempest Ship Bag will be there for you through thick and thin! It has a spacious compartment that can fit your ‘’going out’’ essentials, and comes with a handle and detachable strap so you can carry it as a grab bag, over the shoulder or crossbody, depending on the occasion. This vegan leather boat-shaped bag will give everyone you meet the urge to read the play or go to the theatre in order to know more about the characters displayed on the bag and their fate. Also, it is a limited edition, which means that you may be one of the luckiest people in the world to own such a spectacular bag!, 12cm (H) x 26cm (W) x 11cm (D), Printed and embossed vegan leather, Hand stitched details in vegan leather and cotton, 1 main compartment with zip closure, Comfortable handle, Detachable and adjustable vegan leather shoulder strap, Brass stud feet');
